import{c as o,Q as p,j as a,m as n}from"./chunks/framework.DpF7k2f3.js";const h=JSON.parse('{"title":"第18章 AI应用开发者的未来","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"zh/part5-career/chapter20.md","filePath":"zh/part5-career/chapter20.md","lastUpdated":1779672565000}'),l={name:"zh/part5-career/chapter20.md"};function s(r,t,i,u,e,q){return p(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="第18章-ai应用开发者的未来" tabindex="-1">第18章 AI应用开发者的未来 <a class="header-anchor" href="#第18章-ai应用开发者的未来" aria-label="Permalink to &quot;第18章 AI应用开发者的未来&quot;">​</a></h1><h2 id="本章你能带走什么" tabindex="-1">本章你能带走什么 <a class="header-anchor" href="#本章你能带走什么" aria-label="Permalink to &quot;本章你能带走什么&quot;">​</a></h2><p>读这一章之前，你可能正在焦虑一个灵魂拷问：<strong>&quot;我辛辛苦苦学会的AI应用开发，几年后会不会也被AI取代？&quot;</strong></p><p>这个焦虑很真实。毕竟我们这行天天跟AI打交道，比谁都清楚AI的能力边界在哪。</p><p>读完这章你会知道：</p><ul><li>AI取代哪些工作、为什么不取代另外一些——给你一个分析框架</li><li>为什么AI开发者有独特的&quot;抗取代&quot;优势</li><li>从应用层到基础设施层的进阶路径是什么</li><li>独立开发者/创业者的真实路径和风险</li><li>怎么用&quot;先上车后补票&quot;的逻辑做长期职业规划</li><li>读完这本书后，你该往哪走</li></ul><p>这是全书最后一章。我会给你一个有始有终的收束，但这个收束不是终点——而是一个新起点的开始。</p><hr><h2 id="_18-1-ai会不会取代你" tabindex="-1">18.1 AI会不会取代你？ <a class="header-anchor" href="#_18-1-ai会不会取代你" aria-label="Permalink to &quot;18.1 AI会不会取代你？&quot;">​</a></h2><h3 id="先说结论-会-也不会" tabindex="-1">先说结论：会，也不会 <a class="header-anchor" href="#先说结论-会-也不会" aria-label="Permalink to &quot;先说结论：会，也不会&quot;">​</a></h3><p>我知道这是个废话回答。但真相就是如此——AI会取代一部分工作，不会取代另一部分。关键在于你做的是哪部分。</p><p>让我给你一个分析框架：<strong>工作=任务×复杂度×不可替代性</strong></p><h3 id="什么样的工作最容易被ai取代" tabindex="-1">什么样的工作最容易被AI取代？ <a class="header-anchor" href="#什么样的工作最容易被ai取代" aria-label="Permalink to &quot;什么样的工作最容易被AI取代？&quot;">​</a></h3><p><strong>1. 高度重复、结构化的工作</strong></p><p>比如：</p><ul><li>批量数据标注（虽然现在已经在被取代了）</li><li>标准化报告生成</li><li>简单客服问答</li><li>模板化代码生成</li></ul><p>这类工作的特点是：<strong>有明确规则、有标准答案、重复性高</strong>。AI最擅长的就是这类任务。</p><p><strong>2. 单点技能、缺乏复合能力的工作</strong></p><p>比如：</p><ul><li>只会写Prompt的&quot;Prompt工程师&quot;</li><li>只会调API的&quot;API调用工程师&quot;</li><li>只会用某个框架、不懂业务的技术人</li></ul><p>这类工作的特点是：<strong>能力单一、没有深度、容易被工具替代</strong>。当更好的工具出现时，你就被取代了。</p><p><strong>3. 缺乏业务理解的技术执行</strong></p><p>比如：</p><ul><li>不懂业务场景，纯粹写代码的&quot;代码搬运工&quot;</li><li>不理解用户需求，只会照着PRD实现的开发者</li></ul><p>这类工作的特点是：<strong>技术只是手段，不懂目的</strong>。AI比你更能精准执行指令。</p><h3 id="什么样的工作不容易被ai取代" tabindex="-1">什么样的工作不容易被AI取代？ <a class="header-anchor" href="#什么样的工作不容易被ai取代" aria-label="Permalink to &quot;什么样的工作不容易被AI取代？&quot;">​</a></h3><p><strong>1. 需要判断力与责任承担的工作</strong></p><p>AI可以给你建议，但最终拍板的是人。涉及重大决策的工作——比如判断业务风险、评估法律合规性、决定产品方向——需要人类承担责任。</p><p><strong>2. 需要跨领域整合的工作</strong></p><p>比如：</p><ul><li>&quot;AI+RAG+金融合规&quot;的应用开发</li><li>&quot;AI Agent+医疗场景&quot;的产品设计</li><li>&quot;大模型+制造工艺&quot;的行业落地</li></ul><p>这类工作的价值在于<strong>你对多个领域的理解</strong>，而不是单一技能。</p><p><strong>3. 需要沟通、协调、领导力的工作</strong></p><p>管人、协调资源、推动项目——这些需要情商、经验、人际网络的软技能，AI短期内无法复制。</p><p><strong>4. 需要持续创新的工作</strong></p><p>当技术快速变化时，能快速学习、适应、创新的人永远有价值。<strong>你学东西的速度和能力，才是真正的护城河。</strong></p><h3 id="为什么ai开发者有独特优势" tabindex="-1">为什么AI开发者有独特优势？ <a class="header-anchor" href="#为什么ai开发者有独特优势" aria-label="Permalink to &quot;为什么AI开发者有独特优势？&quot;">​</a></h3><p>说完上面的分析框架，我必须给你一个定心丸：<strong>作为AI应用开发者，你其实站在一个相对安全的位置。</strong></p><p>原因有三：</p><p><strong>第一，你是&quot;用AI的人&quot;，不是&quot;被AI用的人&quot;</strong></p><p>当AI能取代&quot;写简单代码&quot;的工作时，市场会更需要&quot;用AI写出复杂产品&quot;的人。需求不是消失了，而是升级了。</p><p><strong>第二，你的核心能力是&quot;判断+组合&quot;，而不是&quot;执行&quot;</strong></p><p>AI应用开发的本质是什么？是<strong>判断什么场景适合用AI、判断用什么方案、组合各种工具解决问题</strong>。这些能力随着AI进化，只会越来越值钱。</p><p><strong>第三，你离AI最近，最懂怎么用AI</strong></p><p>打个比方：摄影术发明时，有人担心画家失业。但事实是，真正理解光影、构图、表达的画家，不仅没失业，反而身价更高——因为他们懂得把新技术为我所用。</p><p><strong>AI开发者就是新时代的&quot;懂摄影的画家&quot;。</strong></p><h3 id="但别高兴太早——你的护城河需要不断加固" tabindex="-1">但别高兴太早——你的护城河需要不断加固 <a class="header-anchor" href="#但别高兴太早——你的护城河需要不断加固" aria-label="Permalink to &quot;但别高兴太早——你的护城河需要不断加固&quot;">​</a></h3><p>上面说的&quot;优势&quot;不是永久的。你需要持续做三件事：</p><p><strong>1. 从&quot;调API&quot;升级到&quot;设计系统&quot;</strong></p><p>只会调API意味着你只是&quot;AI的操作工&quot;。但如果你能设计RAG架构、能规划Agent协作流程、能优化LLM推理性能——你就从操作工变成了工程师。</p><p><strong>2. 从&quot;技术执行&quot;升级到&quot;业务理解&quot;</strong></p><p>纯技术执行的价值会下降，因为AI的执行能力会越来越强。但如果你理解业务、能用技术解决真实的商业问题——你的价值就不可替代。</p><p><strong>3. 从&quot;单点技能&quot;升级到&quot;T型能力&quot;</strong></p><p>在一个方向深挖，同时对多个相邻领域有了解。比如你是RAG专家，同时懂点产品思维、懂点业务逻辑——这种T型人才永远稀缺。</p><p><strong>一句话总结：AI取代的不是&quot;AI开发者&quot;这个职业，而是&quot;只会执行&quot;的AI开发者。</strong> 持续进化的人，永远不会被取代。</p><hr><h2 id="_18-2-从应用开发到ai基础设施" tabindex="-1">18.2 从应用开发到AI基础设施 <a class="header-anchor" href="#_18-2-从应用开发到ai基础设施" aria-label="Permalink to &quot;18.2 从应用开发到AI基础设施&quot;">​</a></h2><h3 id="为什么你要关心-基础设施" tabindex="-1">为什么你要关心&quot;基础设施&quot;？ <a class="header-anchor" href="#为什么你要关心-基础设施" aria-label="Permalink to &quot;为什么你要关心&quot;基础设施&quot;？&quot;">​</a></h3><p>还记得第1章我们画的AI行业三层架构吗？</p><ul><li><strong>第一层：AI研究</strong>——造模型的人</li><li><strong>第二层：AI基础设施</strong>——造工具的人（训练框架、推理引擎）</li><li><strong>第三层：AI应用开发</strong>——用工具的人</li></ul><p>上一节我说AI应用开发者相对安全，但有一个潜在的威胁你需要注意：<strong>如果AI应用开发的门槛持续下降，你的&quot;护城河&quot;会越来越窄。</strong></p><p>现在用LangChain搭一个RAG系统可能需要写几百行代码。一年后可能只需要50行。再过几年，可能拖拽几个模块就搞定了。</p><p>当工具足够成熟、门槛足够低时，&quot;会用工具&quot;就不再是稀缺技能了。</p><p>这个时候，你要么往价值链上游走，要么往业务深度走。</p><p><strong>往价值链上游走，就是从应用层走向基础设施层。</strong></p><h3 id="应用层-vs-基础设施层-有什么区别" tabindex="-1">应用层 vs 基础设施层：有什么区别？ <a class="header-anchor" href="#应用层-vs-基础设施层-有什么区别" aria-label="Permalink to &quot;应用层 vs 基础设施层：有什么区别？&quot;">​</a></h3><p>我用餐饮行业打个比方：</p><p><strong>应用层</strong> = 开餐厅的。你不需要会种菜、不需要会磨面粉，你需要知道：</p><ul><li>顾客喜欢什么口味</li><li>怎么把食材做成受欢迎的菜</li><li>怎么定价、怎么运营</li></ul><p><strong>基础设施层</strong> = 种菜的、磨面粉的。你需要知道：</p><ul><li>怎么种出好小麦</li><li>怎么磨出好面粉</li><li>怎么让产量更高、成本更低</li></ul><p>两个都很重要，但能力要求和发展路径完全不同。</p><h3 id="从应用层到基础设施层-你可能会遇到什么" tabindex="-1">从应用层到基础设施层，你可能会遇到什么？ <a class="header-anchor" href="#从应用层到基础设施层-你可能会遇到什么" aria-label="Permalink to &quot;从应用层到基础设施层，你可能会遇到什么？&quot;">​</a></h3><p><strong>门槛跳升</strong></p><p>应用层主要是Python + 业务理解。基础设施层需要：</p><ul><li>系统底层知识（C/C++、内存管理、并发编程）</li><li>深度学习框架原理（PyTorch内部机制）</li><li>分布式系统（多卡训练、推理加速）</li><li>硬件知识（GPU架构、TensorCore、内存带宽）</li></ul><p>这不是多学几个框架能解决的，是思维方式的转变。</p><p><strong>角色转变</strong></p><p>应用层：你是&quot;用工具的人&quot;，目标是让工具服务业务。</p><p>基础设施层：你是&quot;造工具的人&quot;，目标是让工具被别人用好。</p><p>造工具需要更抽象的思考能力——你要理解别人怎么用、可能遇到什么问题、怎么设计API让使用更方便。</p><p><strong>市场机会</strong></p><p>说实话，基础设施层的机会比应用层少很多。</p><p>全球做PyTorch开发的人可能几千人，做vLLM优化的可能几百人。这是一个&quot;小而美&quot;的领域，不是大众市场。</p><p>但反过来，这个领域的竞争者也少。一旦进去，护城河很高。</p><h3 id="你需要转基础设施吗" tabindex="-1">你需要转基础设施吗？ <a class="header-anchor" href="#你需要转基础设施吗" aria-label="Permalink to &quot;你需要转基础设施吗？&quot;">​</a></h3><p><strong>不一定。</strong></p><p>我见过很多优秀的AI应用开发者，他们一辈子做应用层，也活得很滋润。</p><p>关键在于你的选择和你的目标：</p><table tabindex="0"><thead><tr><th>如果你是这种人</th><th>建议</th></tr></thead><tbody><tr><td>喜欢钻研底层技术、对系统优化有热情</td><td>可以往基础设施方向探索</td></tr><tr><td>更喜欢解决业务问题、跟人打交道</td><td>深耕应用层就够了</td></tr><tr><td>担心应用层门槛下降、想找更稳定的护城河</td><td>可以学点基础设施知识，但不一定要转行</td></tr><tr><td>已经在一个应用领域做到专家级别</td><td>先把优势巩固，再考虑扩展</td></tr></tbody></table><h3 id="如果你想探索基础设施层-从哪开始" tabindex="-1">如果你想探索基础设施层，从哪开始？ <a class="header-anchor" href="#如果你想探索基础设施层-从哪开始" aria-label="Permalink to &quot;如果你想探索基础设施层，从哪开始？&quot;">​</a></h3><p><strong>三条可行的路径：</strong></p><p><strong>路径1：从应用性能优化切入</strong></p><p>比如你在做RAG应用，发现推理速度慢。与其单纯调参数，你可以深入研究：</p><ul><li>为什么慢？是模型本身慢，还是IO瓶颈？</li><li>有哪些优化手段？量化、剪枝、Batching...</li><li>用什么工具？vLLM、TensorRT-LLM...</li></ul><p>这就是从&quot;用工具&quot;到&quot;优化工具&quot;的自然过渡。</p><p><strong>路径2：从开源贡献开始</strong></p><p>很多基础设施项目是开源的。你可以：</p><ul><li>读懂代码，理解原理</li><li>提交bug修复、文档改进</li><li>逐步参与核心模块开发</li></ul><p>这种方式门槛低、风险小，是很好的试探性探索。</p><p><strong>路径3：从云厂商的Infra岗位切入</strong></p><p>大厂的AI基础设施团队（腾讯云、阿里云、字节云）有大量需求。岗位要求比纯Research低，但比应用层高。</p><p>如果你在大厂做应用开发，内部转岗也是一个选项。</p><p><strong>一句话总结：从应用层到基础设施层是可能的，但需要主动学习和时间投入。不是所有人都要走这条路，但了解它可以帮你在职业规划时多一个选项。</strong></p><hr><h2 id="_18-3-从打工人到独立开发者-创业者" tabindex="-1">18.3 从打工人到独立开发者/创业者 <a class="header-anchor" href="#_18-3-从打工人到独立开发者-创业者" aria-label="Permalink to &quot;18.3 从打工人到独立开发者/创业者&quot;">​</a></h2><h3 id="这条路适合你吗" tabindex="-1">这条路适合你吗？ <a class="header-anchor" href="#这条路适合你吗" aria-label="Permalink to &quot;这条路适合你吗？&quot;">​</a></h3><p>先说个扎心的事实：<strong>独立开发/创业的成功率大概在5%-10%左右</strong>。如果你看到这个数字就打退堂鼓，那我建议你现在就关掉这节，因为它不适合你。</p><p>但如果你说&quot;我知道概率低，但我还是想了解&quot;，那咱们继续。</p><h3 id="独立开发者-创业者的真实路径" tabindex="-1">独立开发者/创业者的真实路径 <a class="header-anchor" href="#独立开发者-创业者的真实路径" aria-label="Permalink to &quot;独立开发者/创业者的真实路径&quot;">​</a></h3><p>我把这条路分成三个阶段，每个阶段有不同重点：</p><p><strong>阶段1：白天上班，晚上造产品（0-1年）</strong></p><p>这是最安全的起步方式。</p><p>核心原则：<strong>不要辞职，先用业余时间验证你的想法</strong>。</p><p>具体做法：</p><ul><li>每周投入10-20小时在side project上</li><li>目标不是&quot;做出完美产品&quot;，而是&quot;快速验证市场是否存在&quot;</li><li>找到100个愿意付费的早期用户，比找到100万投资更重要</li></ul><p>真实案例：我认识一个开发者，在字节上班时，用业余时间做了一个Chrome插件，专门帮AI应用开发者调试Prompt。第一个月就收了300美元。他没有辞职，继续白天上班，晚上迭代。后来这个插件月收入稳定在5000美元，他才考虑辞职全职做。</p><p><strong>阶段2：从小赚到稳定（1-2年）</strong></p><p>当你有了第一批付费用户，下一步是验证这能不能成为一个&quot;business&quot;，而不是一个&quot;project&quot;。</p><p>核心问题：</p><ul><li>你的用户是谁？他们为什么付钱？</li><li>你的竞争对手是谁？你有什么差异化？</li><li>你的成本是多少？能不能盈利？</li></ul><p>真实案例：另一个开发者做了一个AI写作助手。最开始是免费工具，后来加了&quot;AI检测规避&quot;功能开始收费。第一个月赚了800美元，他很兴奋。但后来发现：</p><ul><li>用户主要是学生，用完就走，复购率极低</li><li>竞争对手太多，价格战打不动</li><li>运营成本（API调用费用）比收入还高</li></ul><p>他及时调整了方向——不做通用写作工具，转做&quot;外贸文案专用AI&quot;，面向B端用户。半年后月收入稳定在2万。这说明：<strong>不是所有的&quot;小赚&quot;都能走向&quot;大赚&quot;，方向调整是常态</strong>。</p><p><strong>阶段3：从个人到团队（2-3年）</strong></p><p>如果你的产品过了市场验证、收入稳定，下一步是考虑规模化。</p><p>这里有个坑我必须提醒你：<strong>从&quot;一个人干活&quot;到&quot;带团队干活&quot;，是完全不同的能力要求</strong>。</p><p>很多人技术很强、产品很强，但不会管人、不会融资、不会商务。然后公司就卡在&quot;小而美&quot;上不去。</p><p>要不要突破这个阶段，取决于你的志向。有人愿意一辈子做&quot;一人公司&quot;，年收入几百万、相对自由，也挺好。不是所有人都要IPO。</p><h3 id="独立开发者-创业者的高光与暗面" tabindex="-1">独立开发者/创业者的高光与暗面 <a class="header-anchor" href="#独立开发者-创业者的高光与暗面" aria-label="Permalink to &quot;独立开发者/创业者的高光与暗面&quot;">​</a></h3><p><strong>高光时刻：</strong></p><ul><li>自己的产品自己说了算</li><li>收入天花板没有上限</li><li>可以远程办公、时间自由</li><li>成就感来自于&quot;这个东西是我造的&quot;</li></ul><p><strong>暗面时刻：</strong></p><ul><li>没有稳定工资，焦虑是常态</li><li>一个人要当产品、技术、运营、客服、财务</li><li>失败率很高，心理压力巨大</li><li>社交圈子可能缩小（天天在家办公）</li></ul><p><strong>你真的适合创业吗？</strong></p><p>问自己三个问题：</p><ol><li><p><strong>你能接受多久没有收入？</strong> 如果你三个月没收入就揭不开锅，那现在不是创业的时候。先存够6-12个月的生活费再说。</p></li><li><p><strong>你有一个&quot;非创不可&quot;的想法吗？</strong> 如果你只是觉得&quot;打工没意思&quot;，那大概率撑不下去。创业需要一种近乎偏执的热情。</p></li><li><p><strong>你身边有支持你的人吗？</strong> 创业初期你可能脾气暴躁、疏于陪伴，家人朋友的支持很重要。</p></li></ol><h3 id="给想走这条路的人几个忠告" tabindex="-1">给想走这条路的人几个忠告 <a class="header-anchor" href="#给想走这条路的人几个忠告" aria-label="Permalink to &quot;给想走这条路的人几个忠告&quot;">​</a></h3><p><strong>忠告1：先跑通最小可行性产品（MVP），不要一开始就做&quot;完美产品&quot;</strong></p><p>很多创业者花一年做一个&quot;完美产品&quot;，上线后发现没人用。<strong>你花了多少时间不重要，市场认不认可才重要</strong>。</p><p><strong>忠告2：尽快开始收费，不要迷信&quot;先圈用户再收费&quot;</strong></p><p>免费用户的价值几乎为零。只有愿意付钱的用户才是真用户。</p><p><strong>忠告3：控制成本，不要一开始就租大办公室、招一堆人</strong></p><p>很多创业公司死在&quot;还没赚钱就开始烧钱&quot;上。先一个人、一台电脑跑通商业模式，再考虑扩张。</p><p><strong>忠告4：找到你的&quot;铁杆用户&quot;，而不是&quot;广泛用户&quot;</strong></p><p>先服务好100个铁杆用户，比服务10000个普通用户更有价值。铁杆用户会给你真实反馈、会帮你传播、会在你最困难的时候支持你。</p><p><strong>忠告5：接受失败，但不要浪费失败</strong></p><p>创业失败是大概率事件。但失败不是终点，失败是学习的机会。很多人连续创业、连续失败，最后成功的那次，是因为前面失败的积累。</p><p><strong>一句话总结：独立开发者/创业者的路不是&quot;更高级的打工人&quot;，而是一条完全不同的路。它需要不同的能力、不同的心态、不同的风险承受能力。想清楚再上，上去了就别后悔。</strong></p><hr><h2 id="_18-4-长期职业规划-这本书只是起点" tabindex="-1">18.4 长期职业规划：这本书只是起点 <a class="header-anchor" href="#_18-4-长期职业规划-这本书只是起点" aria-label="Permalink to &quot;18.4 长期职业规划：这本书只是起点&quot;">​</a></h2><h3 id="先回答一个问题-这本书讲了什么" tabindex="-1">先回答一个问题：这本书讲了什么？ <a class="header-anchor" href="#先回答一个问题-这本书讲了什么" aria-label="Permalink to &quot;先回答一个问题：这本书讲了什么？&quot;">​</a></h3><p>如果你让我用一句话概括《AI应用开发入行实战：先上车后补票》，我会说：</p><p><strong>&quot;不要等准备好了再入场，用行动带动成长。&quot;</strong></p><p>这是整本书的核心逻辑，也是第1章开篇就告诉你的那个&quot;反直觉真相&quot;——</p><p>还记得那个&quot;修车师傅&quot;的比喻吗？修车师傅不需要懂发动机原理，AI应用开发者不需要会训练模型。你不需要精通Python再学AI，不需要搞懂所有框架再投简历，不需要成为专家再出来创业。</p><p><strong>&quot;先上车后补票&quot;不是让你&quot;不学无术&quot;，而是让你用真实的反馈来驱动学习，而不是用学习来逃避行动。</strong></p><h3 id="你的职业规划-应该怎么用这个逻辑" tabindex="-1">你的职业规划，应该怎么用这个逻辑？ <a class="header-anchor" href="#你的职业规划-应该怎么用这个逻辑" aria-label="Permalink to &quot;你的职业规划，应该怎么用这个逻辑？&quot;">​</a></h3><p><strong>短期规划（0-2年）：上车</strong></p><p>核心目标：找到AI应用开发的入门位置</p><p>关键行动：</p><ul><li>入职一家有AI业务的公司（哪怕不是核心岗位）</li><li>快速补充岗位急需的技能</li><li>建立&quot;能干活&quot;的基础能力</li><li>积累真实项目经验</li></ul><p>这个阶段的核心是**&quot;先上车&quot;**。不要挑三拣四，先有一个位置再说。</p><p><strong>中期规划（2-5年）：补票</strong></p><p>核心目标：建立不可替代的专业能力</p><p>关键行动：</p><ul><li>在某个方向深挖（Agent、RAG、Infra等）</li><li>参与有挑战性的项目，积累解决问题的能力</li><li>建立行业影响力（技术博客、开源贡献、技术分享）</li><li>开始思考长期方向</li></ul><p>这个阶段的核心是**&quot;补票&quot;**。你已经上车了，现在要补齐你的能力，让位置更稳。</p><p><strong>长期规划（5-10年）：找到你的位置</strong></p><p>核心目标：成为某个领域的专家/管理者/创业者</p><p>关键行动：</p><ul><li>选择适合你的路径（技术专家/技术管理/产品/创业）</li><li>在选择的路径上持续深耕</li><li>建立个人品牌和行业影响力</li><li>持续学习，跟上技术迭代</li></ul><p>这个阶段的核心是**&quot;找到位置&quot;**。你已经不只是一个&quot;AI应用开发者&quot;了，你是一个有清晰定位的专业人士。</p><h3 id="一个动态的职业规划框架" tabindex="-1">一个动态的职业规划框架 <a class="header-anchor" href="#一个动态的职业规划框架" aria-label="Permalink to &quot;一个动态的职业规划框架&quot;">​</a></h3><p>我不喜欢给你一个&quot;五年计划&quot;，因为AI行业变化太快，计划赶不上变化。</p><p>我更推荐一个<strong>动态规划框架</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每6个月问自己三个问题：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 我现在在哪？</span></span>
<span class="line"><span>   - 技术能力在什么水平？</span></span>
<span class="line"><span>   - 在团队/行业的影响力如何？</span></span>
<span class="line"><span>   - 收入和职位到了什么阶段？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 我想去哪？</span></span>
<span class="line"><span>   - 未来6个月我想达到什么状态？</span></span>
<span class="line"><span>   - 这个方向跟我的长期目标一致吗？</span></span>
<span class="line"><span>   - 我对这个方向的热情还够吗？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 我怎么去？</span></span>
<span class="line"><span>   - 为了达到目标，我需要在接下来6个月做什么？</span></span>
<span class="line"><span>   - 我需要学习什么新技能？</span></span>
<span class="line"><span>   - 我需要建立什么人脉？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>每6个月做一次复盘，根据实际情况调整方向。这比一个僵硬的&quot;五年计划&quot;更有用。</p><h3 id="读完这本书后-你该往哪走" tabindex="-1">读完这本书后，你该往哪走？ <a class="header-anchor" href="#读完这本书后-你该往哪走" aria-label="Permalink to &quot;读完这本书后，你该往哪走？&quot;">​</a></h3><p>这是全书最后一章。我不打算给你一个&quot;标准答案&quot;，因为每个人的情况都不同。</p><p>但我可以给你几个&quot;下一步建议&quot;：</p><p><strong>如果你还没有入行：</strong></p><ol><li>用一周时间选定一个技术方向（LangChain、LlamaIndex、或FastAPI）</li><li>花一个月时间做一个完整项目（不是demo，是能跑通的项目）</li><li>开始投简历，不要等&quot;准备好&quot;再投</li></ol><p><strong>如果你刚入行不久：</strong></p><ol><li>专注你当前的工作，把第一个项目做好</li><li>用四象限法则规划你的补课优先级</li><li>开始建立你的&quot;技术雷达&quot;——每周关注行业动态</li></ol><p><strong>如果你工作了一两年：</strong></p><ol><li>开始思考你的长期方向——技术专家？管理？产品？创业？</li><li>在某个方向上开始深挖，不要只停留在&quot;调API&quot;层面</li><li>考虑输出内容，建立你的影响力</li></ol><p><strong>无论你在哪个阶段：</strong></p><ol><li>记住&quot;先上车后补票&quot;的逻辑——行动比准备更重要</li><li>保持学习，但不要让学习变成逃避</li><li>找到你在这行的&quot;不可替代性&quot;</li></ol><h3 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h3><p>写这本书的时候，我一直在想一个问题：<strong>读完这本书的人，真的能入行吗？</strong></p><p>答案是：<strong>不一定。</strong></p><p>书能给你知识，但给不了你行动。书能给你方向，但给不了你坚持。</p><p>读这本书，只是开始。</p><p>真正能让你入行的，是你自己。</p><ul><li>你愿不愿意在别人刷剧的时候去学一个新框架？</li><li>你愿不愿意在别人摸鱼的时候去写一个side project？</li><li>你愿不愿意在被拒绝十次之后，继续投第十一次简历？</li></ul><p>这些，书教不了你。只有你自己能做到。</p><p>但我可以告诉你一件事：<strong>你已经迈出了最重要的一步——你决定进入这个行业。</strong></p><p>还记得第1章说的吗？光是&quot;决定入场&quot;这个念头，就已经超过了90%只是&quot;想想&quot;的人。</p><p>所以，不要浪费你的勇气。</p><p><strong>去干吧。就像你现在正在做的一样。</strong></p><hr><h2 id="本章行动清单" tabindex="-1">本章行动清单 <a class="header-anchor" href="#本章行动清单" aria-label="Permalink to &quot;本章行动清单&quot;">​</a></h2><ol><li><p><strong>做一次&quot;AI取代风险&quot;自检</strong></p><p>对照18.1节的分析框架，评估你当前的工作内容：</p><ul><li>哪些是高风险任务？哪些是低风险任务？</li><li>你需要强化什么能力来提升不可替代性？</li></ul></li><li><p><strong>确定你的&quot;技术深挖方向&quot;</strong></p><p>不要什么都学，选一个方向（Agent、RAG、Infra等）开始深挖。 写下你选择这个方向的理由，以及接下来6个月的学习计划。</p></li><li><p><strong>如果你想走创业路，先做一个side project</strong></p><p>用业余时间验证你的想法。不要辞职，不要租办公室。 目标是在6个月内获得第一个付费用户。</p></li><li><p><strong>设计你的&quot;6个月复盘&quot;机制</strong></p><p>在日历上设置一个每6个月重复的提醒。 届时回答三个问题：我现在在哪？我想去哪？我怎么去？</p></li><li><p><strong>把&quot;先上车后补票&quot;变成你的行动准则</strong></p><p>不要再等&quot;准备好&quot;了。学到60分就开始干，在干的过程中补齐剩下的40分。</p></li><li><p><strong>读完这本书后，写下你的&quot;第一个行动&quot;</strong></p><p>不是&quot;我要好好学习&quot;，而是&quot;我要在接下来一周做XXX&quot;。 把这个行动写下来，贴在你每天能看到的地方。</p></li></ol><hr><h2 id="后记-这不是结束-是开始" tabindex="-1">后记：这不是结束，是开始 <a class="header-anchor" href="#后记-这不是结束-是开始" aria-label="Permalink to &quot;后记：这不是结束，是开始&quot;">​</a></h2><p>恭喜你读完了这本书。</p><p>但就像我之前说的，<strong>这本书不是终点，是一个起点</strong>。</p><p>你从&quot;想了解AI应用开发&quot;，到现在知道了怎么入行、怎么学习、怎么工作、怎么规划未来。你已经拥有了比大多数人更多的知识和方向。</p><p>但知道和做到之间，还有一段路。</p><p>那段路，需要你自己走。</p><p>我没办法替你投简历、替你写代码、替你扛过入职第一天的焦虑、替你熬过第一次项目失败。</p><p>但我可以告诉你一件事：<strong>这条路上，你不是一个人</strong>。</p><p>所有读这本书的人，都在走同一条路。我们都在学习、都在成长、都在寻找自己的位置。</p><p>所以，保持联系。</p><p>也许有一天，你会回来告诉我：</p><ul><li>你成功入行了</li><li>你做出了一个很棒的产品</li><li>你成为了某个领域的专家</li><li>或者你只是想说一声&quot;谢谢你的书帮到我了&quot;</li></ul><p>无论是什么，我都想知道。</p><p>现在，去干吧。</p><p>你的AI开发之路，才刚刚开始。</p>`,220)])])}const d=o(l,[["render",s]]);export{h as __pageData,d as default};
